    "private static void modify(Calendar val, int field, boolean round) {
        if (val.get(Calendar.YEAR) > 280000000) {
            throw new ArithmeticException("Calendar value too large for accurate calculations");
        }


        // ----------------- Fix for LANG-59 ---------------------- START ---------------
        // Manually adjust time for millisecond/second/minute to avoid Calendar field
        // operations which can behave incorrectly across DST transitions.
        if (field == Calendar.MILLISECOND) {
            // Nothing to do for millisecond
            return;
        }
        if (field == Calendar.SECOND) {
            long time = val.getTime().getTime();
            int millis = val.get(Calendar.MILLISECOND);
            if (round) {
                if (millis >= 500) {
                    time += (1000 - millis);
                } else {
                    time -= millis;
                }
            } else {
                time -= millis;
            }
            val.setTime(new Date(time));
            return;
        }
        if (field == Calendar.MINUTE) {
            long time = val.getTime().getTime();
            int seconds = val.get(Calendar.SECOND);
            int millis = val.get(Calendar.MILLISECOND);
            if (round) {
                if (seconds > 30 || (seconds == 30 && millis >= 500)) {
                    time += ((60 - seconds) * 1000L - millis);
                } else {
